INSERT INTO engine_bug_queue (bug_class, title, severity, owner_cluster, root_cause, prevention_rule, probe_type, probe_logic, status, concepts_affected, fixed_in_files, discovered_in_session, row_type) VALUES
('dipole_replay_animations_scenario_type_gap', 'REPLAY_ANIMATIONS re-stamps rotation_start_time on the shared torque-loop group but was gated by an enumerated scenario_type allowlist that omitted pe_external_field and bar_magnet_in_uniform_field, even though both share the same findTorqueLoopGroup()/applyDipoleInFieldState() engine as the two scenario_types that WERE covered', 'MODERATE', 'peter_parker:renderer_primitives', 'FIXED 2026-07-08. REPLAY_ANIMATIONS''s handler in field_3d_renderer.ts gated its rotation_start_time re-stamp on `config.scenario_type === ''torque_on_loop_uniform_field'' || config.scenario_type === ''dipole_in_uniform_field''`, silently excluding pe_external_field and bar_magnet_in_uniform_field despite both routing through the identical shared engine (findTorqueLoopGroup() returns the same torque_loop_group element regardless of scenario_type). Confirmed manifestation: potential_energy_in_external_field STATE_6 (damped_pendulum) -- rotation_start_time stamped once at true state entry, never re-stamped when RESET_TRAJECTORY rebases stateStartTime -- same absolute-stamp desync class as dipole_growth_timer_desync. THE EYE''s dense t=0 read theta=62deg instead of the authored initial 178deg, and the frozen-frame evidence (the canonical reviewer screenshot) showed the fully-settled theta=0deg end-pose instead of a representative in-transit moment, for a state whose entire teaching point is confronting ''aligned=max energy, both zero-torque poses equally stable'' by visibly starting anti-aligned then releasing. A real (narrow) production path was also confirmed: clicking Play again after a state finishes calls rollTimeline() -> RESET_TRAJECTORY + REPLAY_ANIMATIONS, so this scenario_type gap could show real students a stale mid-swing angle on that specific replay gesture for these two concepts.', 'Any postMessage handler in field_3d_renderer.ts that operates on the shared torque-loop group (findTorqueLoopGroup()) must gate on the presence of that group (if (lgR)), NEVER on an enumerated scenario_type allowlist -- the group is built identically by every scenario reusing the dipole/torque engine, and a list will always go stale the next time a new scenario_type reuses the same engine. Additionally, any test harness (THE EYE / screenshotter.ts) that sends RESET_TRAJECTORY to force a clean state-local clock must pair it with REPLAY_ANIMATIONS immediately after, mirroring production''s rollTimeline() convention -- RESET_TRAJECTORY alone does not rebase any one-shot rotation timer.', 'js_eval', 'For any concept whose field_3d_config scenario builds the shared torque-loop group (rotation_mode present in a pef/extras block), run visual:eyes with --dense and read STATE_N''s dense_t00000 frame: theta must match the state''s authored initial theta_deg (or its rotation_init_theta_deg), NOT an already-progressed value. Also read the frozen-frame evidence file for any state with a damped_pendulum/oscillation/theta_sweep rotation_mode: it must not show the fully-settled/limit-cycle end-pose as if it were a fresh mid-arc sample UNLESS the reveal-target ms genuinely implies full settlement.', 'FIXED', ARRAY['potential_energy_in_external_field', 'bar_magnet_in_uniform_field'], ARRAY['src/lib/renderers/field_3d_renderer.ts', 'src/lib/validators/visual/screenshotter.ts'], 'session_2026-07-08_pe_external_field_state5_growth_timer_desync', 'incident')
